\usetikzlibrary{arrows.meta, calc}
\begin{tikzpicture}[scale=1.5]

% --- RECTANGLE ---
\draw[very thick, blue!70] (0,0) rectangle (4,2.5);

% --- DIMENSION LABELS ---
\node[above=0.3cm, fill=white, inner sep=2pt] at (2,2.5) {$8\,\text{cm}$};
\node[below=0.3cm, fill=white, inner sep=2pt] at (2,0) {$8\,\text{cm}$};
\node[left=0.3cm, fill=white, inner sep=2pt, rotate=90] at (0,1.25) {$5\,\text{cm}$};
\node[right=0.3cm, fill=white, inner sep=2pt, rotate=90] at (4,1.25) {$5\,\text{cm}$};

% --- CORNER LABELS ---
\node[below left=0.2cm, fill=white, inner sep=2pt] at (0,0) {A};
\node[below right=0.2cm, fill=white, inner sep=2pt] at (4,0) {B};
\node[above right=0.2cm, fill=white, inner sep=2pt] at (4,2.5) {C};
\node[above left=0.2cm, fill=white, inner sep=2pt] at (0,2.5) {D};

% --- CALCULATIONS BOX ---
\node[draw, rounded corners=4pt, fill=gray!5, text width=8cm, font=\large,
  anchor=north west, inner sep=8pt, align=left]
  at (5.5,2.5) {
  \textbf{Perimeter Calculation}\\[6pt]
  Length = $8\,\text{cm}$\\[4pt]
  Width = $5\,\text{cm}$\\[6pt]
  Perimeter = $2 \times (\text{length} + \text{width})$\\[4pt]
  Perimeter = $2 \times (8 + 5)$\\[4pt]
  Perimeter = $2 \times 13$\\[4pt]
  Perimeter = $\textcolor{red}{26\,\text{cm}}$
};

\end{tikzpicture}
